  <svg viewBox="0 0 700 370" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Ações: a maior parte do retorno vem do "overnight"</text>
    <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">Retorno médio diário do S&amp;P 500 · 1990-2020 (AQR Capital Management)</text>
    <line x1="60" y1="290" x2="640" y2="290" stroke="rgba(255,255,255,.15)" stroke-width="1"/>
